* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: linear-gradient(160deg, #1a0a0a, #2d0a0a, #0a0808); font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: flex-start; justify-content: center; padding: 40px 20px; color: white; }
.app { width: 100%; max-width: 600px; }
h1 { font-size: 28px; font-weight: 900; text-align: center; margin-bottom: 28px; }
.events-list { display: flex; flex-direction: column; gap: 16px; margin-bottom: 28px; }
.event-card { background: rgba(255,255,255,0.06); border: 1px solid rgba(239,68,68,0.2); border-radius: 20px; padding: 20px; position: relative; overflow: hidden; }
.event-card::before { content: ''; position: absolute; inset: 0; background: linear-gradient(135deg, rgba(239,68,68,0.05), transparent); pointer-events: none; }
.ec-header { display: flex; align-items: center; gap: 12px; margin-bottom: 16px; }
.ec-emoji { font-size: 28px; } .ec-name { font-size: 18px; font-weight: 700; flex: 1; } .ec-delete { background: none; border: none; color: rgba(255,255,255,0.3); cursor: pointer; font-size: 18px; } .ec-delete:hover { color: #ef4444; }
.ec-countdown { display: flex; gap: 10px; justify-content: center; }
.ec-unit { text-align: center; background: rgba(255,255,255,0.06); border-radius: 12px; padding: 12px 16px; min-width: 64px; }
.ec-val { font-size: 36px; font-weight: 900; color: #ef4444; display: block; line-height: 1; }
.ec-label { font-size: 11px; color: #6b7280; letter-spacing: 1px; display: block; margin-top: 4px; }
.ec-date { font-size: 12px; color: #6b7280; text-align: center; margin-top: 12px; }
.event-card.finished { border-color: rgba(34,197,94,0.3); }
.event-card.finished .ec-val { color: #22c55e; }
.add-event { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); border-radius: 20px; padding: 24px; }
.add-event h3 { font-size: 16px; font-weight: 700; margin-bottom: 16px; }
.form-row { display: flex; gap: 10px; flex-wrap: wrap; }
#event-name { flex: 2; min-width: 160px; height: 44px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.12); background: rgba(255,255,255,0.06); color: white; padding: 0 14px; font-size: 14px; outline: none; } input:focus { border-color: #ef4444; }
#event-date { flex: 2; min-width: 180px; height: 44px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.12); background: rgba(255,255,255,0.06); color: white; padding: 0 14px; font-size: 14px; outline: none; }
#event-emoji { height: 44px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.12); background: rgba(255,255,255,0.06); color: white; padding: 0 12px; font-size: 16px; outline: none; cursor: pointer; }
.form-row button { height: 44px; padding: 0 20px; border-radius: 12px; border: none; background: #ef4444; color: white; font-weight: 800; cursor: pointer; white-space: nowrap; }

