let events = [
  { id:1, name:'Yeni Yıl 2026', emoji:'🎉', date:'2026-01-01T00:00:00' },
  { id:2, name:'Doğum Günüm', emoji:'🎂', date:'2025-06-15T18:00:00' },
  { id:3, name:'Tatil', emoji:'✈️', date:'2025-07-20T08:00:00' }
];
function getCountdown(dateStr) {
  const diff = new Date(dateStr) - new Date();
  if (diff <= 0) return null;
  const d = Math.floor(diff/86400000);
  const h = Math.floor((diff%86400000)/3600000);
  const m = Math.floor((diff%3600000)/60000);
  const s = Math.floor((diff%60000)/1000);
  return {d,h,m,s};
}
function formatDate(dateStr) { return new Date(dateStr).toLocaleString('tr-TR', {day:'numeric',month:'long',year:'numeric',hour:'2-digit',minute:'2-digit'}); }
function render() {
  document.getElementById('events-list').innerHTML = events.map(e => {
    const cd = getCountdown(e.date);
    const finished = !cd;
    return `
      <div class='event-card ${finished?'finished':''}'>
        <div class='ec-header'><span class='ec-emoji'>${e.emoji}</span><span class='ec-name'>${e.name}</span><button class='ec-delete' onclick='delEvent(${e.id})'>×</button></div>
        ${finished ? `<div style='text-align:center;font-size:18px;color:#22c55e;font-weight:800;padding:8px'>🎊 Bu etkinlik gerçekleşti!</div>` : `
          <div class='ec-countdown'>
            <div class='ec-unit'><span class='ec-val'>${String(cd.d).padStart(2,'0')}</span><span class='ec-label'>GÜN</span></div>
            <div class='ec-unit'><span class='ec-val'>${String(cd.h).padStart(2,'0')}</span><span class='ec-label'>SAAT</span></div>
            <div class='ec-unit'><span class='ec-val'>${String(cd.m).padStart(2,'0')}</span><span class='ec-label'>DAKİKA</span></div>
            <div class='ec-unit'><span class='ec-val'>${String(cd.s).padStart(2,'0')}</span><span class='ec-label'>SANİYE</span></div>
          </div>
        `}
        <div class='ec-date'>${formatDate(e.date)}</div>
      </div>
    `;
  }).join('');
}
function addEvent() {
  const name = document.getElementById('event-name').value.trim();
  const date = document.getElementById('event-date').value;
  const emoji = document.getElementById('event-emoji').value;
  if (!name || !date) return;
  events.push({id:Date.now(),name,emoji,date});
  document.getElementById('event-name').value = '';
  document.getElementById('event-date').value = '';
  render();
}
function delEvent(id) { events = events.filter(e=>e.id!==id); render(); }
render();
setInterval(render, 1000);
